  1→import { useEffect, useRef } from "react";
  2→import {
  3→  Chat,
  4→  ChatSuggestions,
  5→  ChatInput,
  6→  SessionMessage,
  7→  SessionMessagePanel,
  8→  SessionMessages,
  9→  type SlashCommandItem,
 10→} from "reachat";
 11→import { chatComponentCatalog } from "../chat-component-catalog";
 12→import { darkChatTheme } from "../chat-theme";
 13→import { useWorkspaceState } from "../stores/workspace-state";
 14→import { useChatSession } from "../hooks/use-chat-session";
 15→
 16→const COMMAND_ITEMS: SlashCommandItem[] = [
 17→  {
 18→    id: "task",
 19→    label: "task",
 20→    description: "Record a task",
 21→    type: "insert",
 22→    value: "task: ",
 23→  },
 24→  {
 25→    id: "decision",
 26→    label: "decision",
 27→    description: "Record a decision",
 28→    type: "insert",
 29→    value: "decision: ",
 30→  },
 31→  {
 32→    id: "question",
 33→    label: "question",
 34→    description: "Record an open question",
 35→    type: "insert",
 36→    value: "question: ",
 37→  },
 38→];
 39→
 40→export function ChatPage() {
 41→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 42→  const setSidebarHandlers = useWorkspaceState((s) => s.setSidebarHandlers);
 43→
 44→  const chat = useChatSession();
 45→
 46→  // Keep a ref to the latest chat handlers so the effect below doesn't
 47→  // depend on unstable function references (which would cause an infinite
 48→  // render loop: new fn refs → effect fires → setSidebarHandlers → zustand
 49→  // update → AppShell re-renders → ChatPage re-renders → new fn refs → …).
 50→  const chatRef = useRef(chat);
 51→  chatRef.current = chat;
 52→
 53→  // Register sidebar handlers so the shell sidebar can interact with chat
 54→  useEffect(() => {
 55→    setSidebarHandlers({
 56→      activeConversationId: chat.activeConversationId,
 57→      isLoading: chat.isLoading,
 58→      onNewConversation: () => chatRef.current.onNewConversation(),
 59→      onSelectConversation: (id: string) => chatRef.current.onSelectConversation(id),
 60→    });
 61→  }, [chat.activeConversationId, chat.isLoading]);
 62→
 63→  // Cleanup sidebar handlers on unmount
 64→  useEffect(() => {
 65→    return () => {
 66→      setSidebarHandlers(undefined);
 67→    };
 68→  }, []);
 69→
 70→  return (
 71→    <section className="reachat-page">
 72→      {chat.pendingFile ? (
 73→        <div className="workspace-toolbar">
 74→          <div className="pending-file">
 75→            Attached: {chat.pendingFile.name}
 76→            <button type="button" onClick={() => chat.onUploadFile(undefined as unknown as File)}>
 77→              Clear
 78→            </button>
 79→          </div>
 80→        </div>
 81→      ) : undefined}
 82→
 83→      <div className="chat-main">
 84→        <Chat
 85→          viewType="chat"
 86→          theme={darkChatTheme}
 87→          sessions={chat.sessions}
 88→          activeSessionId={chat.activeSession.id}
 89→          components={chatComponentCatalog}
 90→          isLoading={chat.isLoading}
 91→          onSendMessage={chat.onSendMessage}
 92→          onStopMessage={chat.onStopMessage}
 93→          onFileUpload={chat.onUploadFile}
 94→        >
 95→          <SessionMessagePanel>
 96→            <SessionMessages>
 97→              {(conversations) =>
 98→                conversations.map((conversation, index) => {
 99→                  const isInherited = chat.inheritedMessageIds.has(conversation.id);
100→                  const isLastInherited = isInherited
101→                    && index < conversations.length - 1
102→                    && !chat.inheritedMessageIds.has(conversations[index + 1].id);
103→                  return (
104→                    <div
105→                      key={conversation.id}
106→                      data-message-id={conversation.id}
107→                      className={isInherited ? "message-inherited" : undefined}
108→                    >
109→                      <SessionMessage
110→                        conversation={conversation}
111→                        isLast={index === conversations.length - 1}
112→                      />
113→                      {!isInherited && conversation.response && onboardingState === "complete" ? (
114→                        <button
115→                          type="button"
116→                          className="branch-message-btn"
117→                          onClick={() => void chat.onBranchFromMessage(conversation.id)}
118→                          disabled={chat.isLoading || chat.branchingFromId !== undefined}
119→                          title="Branch from here"
