#### Step 9: Frontend -- Create `ReferencedEntityCard` component

**File:** `/Users/marcus/conductor/workspaces/brain/tyler-v1/app/src/client/components/chat/ReferencedEntityCard.tsx` (new file)

This component renders above the chat messages area. It has two modes:

1. **From view-state** (pre-first-message): Fetches entity detail from API, shows loading state.
2. **From conversation response** (post-first-message or reloaded conversation): Uses the `ReferencedEntitySummary` directly.

```typescript
import { useEffect, useState } from "react";
import type { EntityDetailResponse, ReferencedEntitySummary } from "../../../shared/contracts";
import { EntityBadge } from "../graph/EntityBadge";

type Props = {
  entityId?: string;                        // from view-state (pre-send)
  conversationRef?: ReferencedEntitySummary; // from conversation response
  workspaceId: string;
};

export function ReferencedEntityCard({ entityId, conversationRef, workspaceId }: Props) {
  const [detail, setDetail] = useState<{ kind: string; name: string; status?: string } | undefined>();
  const [loading, setLoading] = useState(false);

  // Derive display data from whichever source is available
  const displayEntity = conversationRef ?? detail;

  useEffect(() => {
    if (conversationRef || !entityId) return;
    setLoading(true);
    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
      .then(r => r.json() as Promise<EntityDetailResponse>)
      .then(data => {
        setDetail({
          kind: data.entity.kind,
          name: data.entity.name,
          status: data.entity.data.status as string | undefined,
        });
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [entityId, conversationRef, workspaceId]);

  if (!displayEntity && !loading) return undefined;

  return (
    <div className="referenced-entity-card">
      {loading ? (
        <span>Loading entity...</span>
      ) : displayEntity ? (
        <>
          <EntityBadge kind={displayEntity.kind as any} />
          <span className="referenced-entity-name">{displayEntity.name}</span>
          {displayEntity.status ? (
            <span className="referenced-entity-status">{displayEntity.status}</span>
          ) : undefined}
        </>
      ) : undefined}
    </div>
  );
}
```

**Complexity:** Medium (~60 lines including CSS)

