355→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
356→  LET $query = string::lowercase(string::trim($q));
357→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
358→
359→  LET $task_rows = SELECT
360→    id,
361→    "task" AS kind,
362→    title AS text,
363→    extraction_confidence AS confidence,
364→    source_message AS sourceMessage,
365→    priority,
366→    created_at
367→  FROM task
368→  WHERE workspace = $workspace
369→    AND extraction_confidence != NONE
370→    AND string::contains(string::lowercase(title), $query)
371→  ORDER BY created_at DESC
372→  LIMIT $safe_limit;
373→
374→  LET $decision_rows = SELECT
375→    id,
376→    "decision" AS kind,
377→    summary AS text,
378→    extraction_confidence AS confidence,
379→    source_message AS sourceMessage,
380→    priority,
381→    created_at
382→  FROM decision
383→  WHERE workspace = $workspace
384→    AND extraction_confidence != NONE
385→    AND string::contains(string::lowercase(summary), $query)
386→  ORDER BY created_at DESC
387→  LIMIT $safe_limit;
388→
389→  LET $question_rows = SELECT
390→    id,
391→    "question" AS kind,
392→    text AS text,
393→    extraction_confidence AS confidence,
394→    source_message AS sourceMessage,
395→    priority,
396→    created_at
397→  FROM question
398→  WHERE workspace = $workspace
399→    AND extraction_confidence != NONE
400→    AND string::contains(string::lowercase(text), $query)
401→  ORDER BY created_at DESC
402→  LIMIT $safe_limit;
403→
404→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
405→};
