407→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
408→  LET $query = string::lowercase(string::trim($q));
409→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
410→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
411→
412→  LET $task_rows = SELECT
413→    id,
414→    "task" AS kind,
415→    title AS text,
416→    extraction_confidence AS confidence,
417→    source_message AS sourceMessage,
418→    priority,
419→    created_at
420→  FROM task
421→  WHERE workspace = $workspace
422→    AND extraction_confidence != NONE
423→    AND id IN $project_entity_ids
424→    AND string::contains(string::lowercase(title), $query)
425→  ORDER BY created_at DESC
426→  LIMIT $safe_limit;
427→
428→  LET $decision_rows = SELECT
429→    id,
430→    "decision" AS kind,
431→    summary AS text,
432→    extraction_confidence AS confidence,
433→    source_message AS sourceMessage,
434→    priority,
435→    created_at
436→  FROM decision
437→  WHERE workspace = $workspace
438→    AND extraction_confidence != NONE
439→    AND id IN $project_entity_ids
440→    AND string::contains(string::lowercase(summary), $query)
441→  ORDER BY created_at DESC
442→  LIMIT $safe_limit;
443→
444→  LET $question_rows = SELECT
445→    id,
446→    "question" AS kind,
447→    text AS text,
448→    extraction_confidence AS confidence,
449→    source_message AS sourceMessage,
450→    priority,
451→    created_at
452→  FROM question
453→  WHERE workspace = $workspace
454→    AND extraction_confidence != NONE
455→    AND id IN $project_entity_ids
456→    AND string::contains(string::lowercase(text), $query)
457→  ORDER BY created_at DESC
458→  LIMIT $safe_limit;
459→
460→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
461→};
