463→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
464→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
465→  RETURN SELECT id, role, text, createdAt
466→  FROM message
467→  WHERE conversation = $conversation
468→  ORDER BY createdAt DESC
469→  LIMIT $safe_limit;
470→};
