472→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
473→  RETURN SELECT
474→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
475→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
476→  FROM $entity;
477→};
