  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import type { ChatMessageResponse } from "../../shared/contracts";
  4→import { HttpError } from "../http/errors";
  5→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
  6→import { parseIncomingMessageRequest } from "../http/parsing";
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import type { ServerDependencies } from "../runtime/types";
  9→import type { ConversationRow, WorkspaceRow } from "../extraction/types";
 10→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 11→import { deriveMessageTitle } from "../workspace/conversation-sidebar";
 12→import { processChatMessage } from "./chat-processor";
 13→
 14→export function createChatIngressHandlers(deps: ServerDependencies): {
 15→  handlePostChatMessage: (request: Request) => Promise<Response>;
 16→  handleChatStream: (messageId: string) => Response;
 17→} {
 18→  return {
 19→    handlePostChatMessage: (request: Request) => handlePostChatMessage(deps, request),
 20→    handleChatStream: (messageId: string) => deps.sse.handleStreamRequest(messageId),
 21→  };
 22→}
 23→
 24→async function handlePostChatMessage(deps: ServerDependencies, request: Request): Promise<Response> {
 25→  const startedAt = performance.now();
 26→  logInfo("chat.message.ingress.started", "Chat message ingress started");
 27→
 28→  let parsed: Awaited<ReturnType<typeof parseIncomingMessageRequest>>;
 29→  try {
 30→    parsed = await parseIncomingMessageRequest(request);
 31→  } catch (error) {
 32→    logError("chat.message.parse.failed", "Parsing incoming chat message failed", error);
 33→    const errorText = error instanceof Error ? error.message : "invalid request body";
 34→    return jsonError(errorText, 400);
 35→  }
 36→
 37→  if (!parsed.ok) {
 38→    return jsonError(parsed.error, 400);
 39→  }
 40→
 41→  const conversationId = parsed.data.conversationId ?? randomUUID();
 42→  const messageId = randomUUID();
 43→  const workspaceId = parsed.data.workspaceId;
 44→  const userText = parsed.data.text.trim();
 45→  const onboardingAction = parsed.data.onboardingAction;
 46→  const messageText = userText.length > 0 ? userText : `Uploaded document: ${parsed.data.attachment?.fileName ?? "attachment"}`;
 47→  const userMessageRecord = new RecordId("message", randomUUID());
 48→
 49→  logDebug("http.request.validated", "Chat message request validated", {
 50→    workspaceId,
 51→    conversationId,
 52→    hasAttachment: parsed.data.attachment !== undefined,
 53→  });
 54→
 55→  let workspaceRecord: RecordId<"workspace", string>;
 56→
 57→  try {
 58→    logInfo("chat.message.persist.started", "Persisting user chat message", {
 59→      workspaceId,
 60→      conversationId,
 61→      messageId,
 62→    });
 63→
 64→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 65→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
 66→    if (!workspace) {
 67→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
 68→    }
 69→
 70→    const now = new Date();
 71→    const conversationRecord = new RecordId("conversation", conversationId);
 72→    const existingConversation = await deps.surreal.select<ConversationRow>(conversationRecord);
 73→
 74→    const transaction = await deps.surreal.beginTransaction();
 75→    try {
 76→      if (existingConversation) {
 77→        if (!existingConversation.workspace) {
 78→          throw new HttpError(500, "conversation is missing workspace scope");
 79→        }
 80→
 81→        if (existingConversation.workspace.id !== workspaceRecord.id) {
 82→          throw new HttpError(400, "conversation scope does not match workspaceId");
 83→        }
 84→
 85→        await transaction.update(conversationRecord).merge({
 86→          updatedAt: now,
 87→        });
 88→      } else {
 89→        await transaction.create(conversationRecord).content({
 90→          createdAt: now,
 91→          updatedAt: now,
 92→          workspace: workspaceRecord,
 93→          title: deriveMessageTitle(messageText),
 94→          title_source: "message",
 95→          ...(workspace.onboarding_complete ? {} : { source: "onboarding" }),
 96→        });
 97→      }
 98→
 99→      await transaction.create(userMessageRecord).content({
100→        conversation: conversationRecord,
101→        role: "user",
102→        text: messageText,
103→        createdAt: now,
104→        clientMessageId: parsed.data.clientMessageId,
105→      });
106→
107→      if (!workspace.onboarding_complete) {
108→        await transaction.update(workspaceRecord).merge({
109→          onboarding_turn_count: workspace.onboarding_turn_count + 1,
110→          updated_at: now,
111→        });
112→      }
113→
114→      await transaction.commit();
115→    } catch (error) {
116→      await transaction.cancel();
117→      throw error;
118→    }
119→
120→    logInfo("chat.message.persist.completed", "User chat message persisted", {
121→      workspaceId,
122→      conversationId,
123→      messageId,
124→      userMessageId: userMessageRecord.id as string,
125→    });
126→  } catch (error) {
127→    if (error instanceof HttpError) {
128→      logWarn("chat.message.persist.http_error", "Chat message persistence failed with client-facing error", {
129→        workspaceId,
130→        conversationId,
131→        messageId,
132→        statusCode: error.status,
133→      });
134→      return jsonError(error.message, error.status);
135→    }
136→
137→    logError("chat.message.persist.failed", "Persisting user chat message failed", error, {
138→      workspaceId,
139→      conversationId,
140→      messageId,
141→    });
142→    const errorText = error instanceof Error ? error.message : "failed to persist user message";
143→    return jsonError(errorText, 500);
144→  }
145→
146→  deps.sse.registerMessage(messageId);
147→
148→  logInfo("chat.message.process.started", "Async chat processing started", {
149→    workspaceId,
150→    conversationId,
151→    messageId,
152→  });
153→
154→  void processChatMessage({
155→    deps,
156→    conversationId,
157→    messageId,
158→    workspaceRecord,
159→    userMessageRecord,
160→    userText: messageText,
161→    attachment: parsed.data.attachment,
162→    ...(onboardingAction ? { onboardingAction } : {}),
163→  });
164→
165→  const response: ChatMessageResponse = {
166→    messageId,
167→    userMessageId: userMessageRecord.id as string,
168→    conversationId,
169→    workspaceId,
170→    streamUrl: `/api/chat/stream/${messageId}`,
171→  };
172→
173→  logInfo("chat.message.ingress.completed", "Chat message ingress completed", {
174→    workspaceId,
175→    conversationId,
176→    messageId,
177→    durationMs: elapsedMs(startedAt),
178→  });
179→
180→  return jsonResponse(response, 200);
181→}
