133→function toRecordIdString(record: RecordId<string, string>): string {
134→  return record.id as string;
135→}
136→
137→function toIsoString(value: string | Date): string {
138→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
139→}
140→
141→function normalizeSearchValue(value: string): string {
142→  return value
143→    .trim()
144→    .toLowerCase()
145→    .replace(/[^a-z0-9\s]/g, " ")
146→    .replace(/\s+/g, " ");
147→}
