147→  async function loadConversation(wsId: string, conversationId: string) {
148→    try {
149→      const response = await fetch(
150→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
151→      );
152→      if (!response.ok) {
153→        const body = await response.text();
154→        setErrorMessage(body);
155→        return;
156→      }
157→
158→      const payload = (await response.json()) as WorkspaceConversationResponse;
159→      const conversations: Session["conversations"] = [];
160→      let latestSuggestions: string[] = [];
161→      const inheritedIds = new Set<string>();
162→
163→      for (const message of payload.messages) {
164→        if (message.role === "user") {
165→          conversations.push({
166→            id: message.id,
167→            question: message.text,
168→            createdAt: new Date(message.createdAt),
169→          });
170→          if (message.inherited) {
171→            inheritedIds.add(message.id);
172→          }
173→          continue;
174→        }
175→
176→        const last = conversations[conversations.length - 1];
177→        if (last && !last.response) {
178→          last.response = message.text;
179→          last.updatedAt = new Date(message.createdAt);
180→          latestSuggestions =
181→            message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
182→          if (message.inherited) {
183→            inheritedIds.add(last.id);
184→          }
185→          continue;
186→        }
187→
188→        conversations.push({
189→          id: `assistant-${message.id}`,
190→          question: "",
191→          response: message.text,
192→          createdAt: new Date(message.createdAt),
193→        });
194→        if (message.inherited) {
195→          inheritedIds.add(`assistant-${message.id}`);
196→        }
197→        latestSuggestions =
198→          message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
199→      }
200→
201→      setInheritedMessageIds(inheritedIds);
202→      setSessions([
203→        {
204→          id: "main",
205→          title: workspaceName ?? "Workspace Chat",
206→          createdAt: new Date(),
207→          updatedAt: new Date(),
208→          conversations,
209→        },
210→      ]);
211→
212→      setSuggestions(
213→        latestSuggestions.map((content, index) => ({
214→          id: `conv-suggestion-${index}-${content}`,
215→          content,
216→        })),
217→      );
218→
219→      setActiveConversationId(conversationId);
220→      setBackendConversationId(conversationId);
221→    } catch (error) {
222→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
223→      setErrorMessage(messageText);
224→    }
225→  }
