301→export async function listConversationEntities(input: {
302→  surreal: Surreal;
303→  conversationRecord: RecordId<"conversation", string>;
304→  workspaceRecord: RecordId<"workspace", string>;
305→  limit: number;
306→  inheritedEntityIds?: RecordId[];
307→}): Promise<ConversationEntity[]> {
308→  const [rows] = await input.surreal
309→    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
310→      [
311→        "SELECT `in`, out, confidence, extracted_at",
312→        "FROM extraction_relation",
313→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
314→        "ORDER BY extracted_at DESC",
315→        "LIMIT $limit;",
316→      ].join(" "),
317→      {
318→        conversation: input.conversationRecord,
319→        limit: input.limit,
320→      },
321→    )
322→    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;
323→
324→  const items: ConversationEntity[] = [];
325→  const seen = new Set<string>();
326→
327→  for (const row of rows) {
328→    const table = row.out.table.name as GraphEntityTable;
329→    if (
330→      table !== "workspace" &&
331→      table !== "project" &&
332→      table !== "person" &&
333→      table !== "feature" &&
334→      table !== "task" &&
335→      table !== "decision" &&
336→      table !== "question"
337→    ) {
338→      continue;
339→    }
340→
341→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
342→    if (!scoped) {
343→      continue;
344→    }
345→
346→    const entityKey = `${table}:${toRecordIdString(row.out)}`;
347→    if (seen.has(entityKey)) {
348→      continue;
349→    }
350→
351→    const name = await readEntityName(input.surreal, row.out);
352→    if (!name) {
353→      continue;
354→    }
355→
356→    items.push({
357→      id: toRecordIdString(row.out),
358→      kind: table,
359→      name,
360→      confidence: row.confidence,
361→      sourceMessageId: toRecordIdString(row.in),
362→    });
363→    seen.add(entityKey);
364→  }
365→
366→  // Merge inherited entities from parent conversation when branch has sparse context
367→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
368→    const [inheritedRows] = await input.surreal
369→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
370→        [
371→          "SELECT `in`, out, confidence, extracted_at",
372→          "FROM extraction_relation",
373→          "WHERE out IN $entityIds",
374→          "ORDER BY extracted_at DESC",
375→          "LIMIT $limit;",
376→        ].join(" "),
377→        { entityIds: input.inheritedEntityIds, limit: input.limit },
378→      )
379→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
380→
381→    for (const row of inheritedRows) {
382→      const table = row.out.table.name as GraphEntityTable;
383→      if (
384→        table !== "workspace" &&
385→        table !== "project" &&
386→        table !== "person" &&
387→        table !== "feature" &&
388→        table !== "task" &&
389→        table !== "decision" &&
390→        table !== "question"
391→      ) {
392→        continue;
393→      }
394→
395→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
396→      if (seen.has(entityKey)) continue;
397→
398→      const name = await readEntityName(input.surreal, row.out);
399→      if (!name) continue;
400→
401→      items.push({
402→        id: toRecordIdString(row.out),
403→        kind: table,
404→        name,
405→        confidence: row.confidence,
406→        sourceMessageId: toRecordIdString(row.in),
407→      });
408→      seen.add(entityKey);
409→    }
410→  }
411→
412→  return items;
413→}
