 914→export async function getEntityDetail(input: {
 915→  surreal: Surreal;
 916→  workspaceRecord: RecordId<"workspace", string>;
 917→  entityRecord: GraphEntityRecord;
 918→}): Promise<EntityDetail> {
 919→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.entityRecord);
 920→  if (!scoped) {
 921→    throw new Error("entity is outside the current workspace scope");
 922→  }
 923→
 924→  const table = input.entityRecord.table.name as GraphEntityTable;
 925→  const row = await input.surreal.select<Record<string, unknown>>(input.entityRecord);
 926→  if (!row) {
 927→    throw new Error(`entity not found: ${table}:${toRecordIdString(input.entityRecord)}`);
 928→  }
 929→
 930→  const name = await readEntityName(input.surreal, input.entityRecord);
 931→  if (!name) {
 932→    throw new Error(`entity has no readable name field: ${table}:${toRecordIdString(input.entityRecord)}`);
 933→  }
 934→
 935→  const relationships = await listEntityNeighbors({
 936→    surreal: input.surreal,
 937→    workspaceRecord: input.workspaceRecord,
 938→    entityRecord: input.entityRecord,
 939→    limit: 40,
 940→  });
 941→
 942→  const [provenanceRows] = await input.surreal
 943→    .query<[
 944→      Array<{
 945→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
 946→        confidence: number;
 947→        extracted_at: string | Date;
 948→        evidence?: string;
 949→        evidence_source?: RecordId<"message", string>;
 950→        resolved_from?: RecordId<"message", string>;
 951→        from_text?: string;
 952→      }>,
 953→    ]>(
 954→      [
 955→        "SELECT `in`, confidence, extracted_at, evidence, evidence_source, resolved_from, from_text",
 956→        "FROM extraction_relation",
 957→        "WHERE out = $entity",
 958→        "AND (",
 959→        "  `in` IN (",
 960→        "    SELECT VALUE id",
 961→        "    FROM message",
 962→        "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
 963→        "  )",
 964→        "  OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
 965→        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
 966→        ")",
 967→        "ORDER BY extracted_at DESC",
 968→        "LIMIT 40;",
 969→      ].join(" "),
 970→      {
 971→        workspace: input.workspaceRecord,
 972→        entity: input.entityRecord,
 973→      },
 974→    )
 975→    .collect<[
 976→      Array<{
 977→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
 978→        confidence: number;
 979→        extracted_at: string | Date;
 980→        evidence?: string;
 981→        evidence_source?: RecordId<"message", string>;
 982→        resolved_from?: RecordId<"message", string>;
 983→        from_text?: string;
 984→      }>,
 985→    ]>();
 986→
 987→  const provenance = provenanceRows.map((row) => ({
 988→    sourceId: toRecordIdString(row.in),
 989→    sourceKind: row.in.table.name === "document_chunk"
 990→      ? "document_chunk"
 991→      : row.in.table.name === "git_commit"
 992→        ? "git_commit"
 993→        : "message",
 994→    confidence: row.confidence,
 995→    extractedAt: toIsoString(row.extracted_at),
 996→    ...(row.evidence ? { evidence: row.evidence } : {}),
 997→    ...(row.evidence_source ? { evidenceSource: toRecordIdString(row.evidence_source) } : {}),
 998→    ...(row.resolved_from ? { resolvedFrom: toRecordIdString(row.resolved_from) } : {}),
 999→    ...(row.from_text ? { fromText: row.from_text } : {}),
1000→  } satisfies EntityProvenance));
1001→
1002→  return {
1003→    entity: {
1004→      id: toRecordIdString(input.entityRecord),
1005→      kind: table,
1006→      name,
1007→      data: row,
1008→    },
1009→    relationships,
1010→    provenance,
1011→  };
1012→}
