  1→import { useEffect, useState } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import type { EntityCategory, EntityDetailResponse, EntityKind, EntityPriority } from "../../../shared/contracts";
  4→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES } from "../../../shared/contracts";
  5→import { CategoryBadge } from "./CategoryBadge";
  6→import { DescriptionSection } from "./DescriptionSection";
  7→import { EntityBadge } from "./EntityBadge";
  8→import { RelationshipList } from "./RelationshipList";
  9→import { ProvenanceSection } from "./ProvenanceSection";
 10→import { useViewState } from "../../stores/view-state";
 11→import { confirmDecision, overrideDecision, markTaskComplete, setEntityPriority } from "../../graph/actions";
 12→
 13→const CONFIRMABLE_STATUSES = new Set(["extracted", "proposed", "provisional", "inferred"]);
 14→
 15→export function EntityDetailPanel({
 16→  entityId,
 17→  workspaceId,
 18→  onClose,
 19→  onEntityClick,
 20→}: {
 21→  entityId: string;
 22→  workspaceId: string;
 23→  onClose: () => void;
 24→  onEntityClick: (entityId: string) => void;
 25→}) {
 26→  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
 27→  const [loading, setLoading] = useState(true);
 28→  const [error, setError] = useState<string | undefined>();
 29→  const [actionPending, setActionPending] = useState(false);
 30→  const navigateToChat = useViewState((s) => s.navigateToChat);
 31→  const navigate = useNavigate();
 32→
 33→  useEffect(() => {
 34→    setLoading(true);
 35→    setError(undefined);
 36→
 37→    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
 38→      .then(async (response) => {
 39→        if (!response.ok) {
 40→          const body = await response.text();
 41→          throw new Error(body);
 42→        }
 43→        return response.json() as Promise<EntityDetailResponse>;
 44→      })
 45→      .then((data) => {
 46→        setDetail(data);
 47→        setLoading(false);
 48→      })
 49→      .catch((err) => {
 50→        setError(err instanceof Error ? err.message : "Failed to load entity");
 51→        setLoading(false);
 52→      });
 53→  }, [entityId, workspaceId]);
 54→
 55→  function handleJumpToMessage(messageId: string) {
 56→    navigateToChat(messageId);
 57→    void navigate({ to: "/" });
 58→  }
 59→
 60→  async function handleConfirm() {
 61→    if (!detail || actionPending) return;
 62→    setActionPending(true);
 63→    try {
 64→      await confirmDecision(workspaceId, entityId);
 65→      setDetail((prev) =>
 66→        prev
 67→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
 68→          : prev,
 69→      );
 70→    } finally {
 71→      setActionPending(false);
 72→    }
 73→  }
 74→
 75→  async function handleOverride() {
 76→    if (!detail || actionPending) return;
 77→    const newSummary = window.prompt("New decision summary:");
 78→    if (!newSummary) return;
 79→    setActionPending(true);
 80→    try {
 81→      await overrideDecision(workspaceId, entityId, newSummary);
 82→      setDetail((prev) =>
 83→        prev
 84→          ? {
 85→              ...prev,
 86→              entity: {
 87→                ...prev.entity,
 88→                name: newSummary,
 89→                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
 90→              },
 91→            }
 92→          : prev,
 93→      );
 94→    } finally {
 95→      setActionPending(false);
 96→    }
 97→  }
 98→
 99→  async function handleComplete() {
100→    if (!detail || actionPending) return;
101→    setActionPending(true);
102→    try {
103→      await markTaskComplete(workspaceId, entityId);
104→      setDetail((prev) =>
105→        prev
106→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
107→          : prev,
108→      );
109→    } finally {
110→      setActionPending(false);
111→    }
112→  }
113→
114→  if (loading) {
115→    return (
116→      <aside className="entity-detail-panel">
117→        <p className="entity-detail-meta">Loading...</p>
118→      </aside>
119→    );
120→  }
121→
122→  if (error || !detail) {
123→    return (
124→      <aside className="entity-detail-panel">
125→        <div className="entity-detail-header">
126→          <p className="entity-detail-meta">{error ?? "Entity not found"}</p>
127→          <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
128→        </div>
129→      </aside>
130→    );
131→  }
132→
133→  const kind = detail.entity.kind as EntityKind;
134→  const status = (detail.entity.data.status as string | undefined) ?? "";
135→  const rationale = detail.entity.data.rationale as string | undefined;
136→
137→  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
138→  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
139→  const showComplete = kind === "task" && status !== "done";
140→
141→  return (
142→    <aside className="entity-detail-panel">
143→      <div className="entity-detail-header">
144→        <div>
145→          <EntityBadge kind={kind} />
146→          <h3>{detail.entity.name}</h3>
147→        </div>
148→        <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
149→      </div>
150→
151→      <div className="entity-detail-section">
152→        <h4>Metadata</h4>
153→        <dl className="entity-detail-meta">
154→          {status ? (
155→            <>
156→              <dt>Status</dt>
157→              <dd>{status}</dd>
158→            </>
159→          ) : undefined}
160→          {typeof detail.entity.data.category === "string" && (ENTITY_CATEGORIES as readonly string[]).includes(detail.entity.data.category) ? (
161→            <>
162→              <dt>Category</dt>
163→              <dd><CategoryBadge category={detail.entity.data.category as EntityCategory} /></dd>
164→            </>
165→          ) : undefined}
166→          {detail.entity.data.confidence !== undefined ? (
167→            <>
168→              <dt>Confidence</dt>
169→              <dd>{(detail.entity.data.confidence as number).toFixed(2)}</dd>
170→            </>
171→          ) : undefined}
172→          {detail.entity.data.created_at ? (
173→            <>
174→              <dt>Created</dt>
175→              <dd>{new Date(detail.entity.data.created_at as string).toLocaleDateString()}</dd>
176→            </>
177→          ) : undefined}
178→          {detail.entity.data.owner_name ? (
179→            <>
180→              <dt>Owner</dt>
181→              <dd>{detail.entity.data.owner_name as string}</dd>
182→            </>
183→          ) : undefined}
184→          {(kind === "task" || kind === "decision" || kind === "question") ? (
185→            <>
186→              <dt>Priority</dt>
187→              <dd>
188→                <select
189→                  value={(detail.entity.data.priority as string | undefined) ?? ""}
190→                  disabled={actionPending}
191→                  onChange={async (e) => {
192→                    const value = e.target.value as EntityPriority;
193→                    if (!value) return;
194→                    setActionPending(true);
195→                    try {
196→                      await setEntityPriority(workspaceId, entityId, value);
197→                      setDetail((prev) =>
198→                        prev
199→                          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, priority: value } } }
200→                          : prev,
201→                      );
202→                    } finally {
203→                      setActionPending(false);
204→                    }
205→                  }}
206→                >
207→                  <option value="" disabled>—</option>
208→                  {ENTITY_PRIORITIES.map((p) => (
209→                    <option key={p} value={p}>{p}</option>
210→                  ))}
211→                </select>
212→              </dd>
213→            </>
214→          ) : undefined}
215→        </dl>
216→      </div>
217→
218→      <DescriptionSection data={detail.entity.data} kind={kind} onEntityClick={onEntityClick} />
219→
220→      {rationale ? (
221→        <div className="entity-detail-section">
222→          <h4>Rationale</h4>
223→          <p className="entity-detail-meta">{rationale}</p>
224→        </div>
225→      ) : undefined}
226→
227→      <RelationshipList relationships={detail.relationships} onEntityClick={onEntityClick} />
228→
229→      <ProvenanceSection provenance={detail.provenance} onJumpToMessage={handleJumpToMessage} />
230→
231→      {(showConfirm || showOverride || showComplete) ? (
232→        <div className="entity-detail-actions">
233→          {showConfirm ? (
234→            <button type="button" disabled={actionPending} onClick={handleConfirm}>
235→              Confirm
236→            </button>
237→          ) : undefined}
238→          {showOverride ? (
239→            <button type="button" disabled={actionPending} onClick={handleOverride}>
240→              Override
241→            </button>
242→          ) : undefined}
243→          {showComplete ? (
244→            <button type="button" disabled={actionPending} onClick={handleComplete}>
245→              Mark Complete
246→            </button>
247→          ) : undefined}
248→        </div>
249→      ) : undefined}
250→    </aside>
251→  );
252→}
