459→}): Promise<WorkspaceDecisionSummary[]> {
460→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
461→  const projectRecords = projects.map((project) => project.id);
462→  const projectById = new Map(projects.map((project) => [toRecordIdString(project.id), project.name]));
463→
464→  const [rows] = await input.surreal
465→    .query<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>(
466→      [
467→        "SELECT id, summary, status, priority, created_at",
468→        "FROM decision",
469→        "WHERE workspace = $workspace",
470→        "ORDER BY created_at DESC",
471→        "LIMIT $limit;",
472→      ].join(" "),
473→      {
474→        workspace: input.workspaceRecord,
475→        limit: input.limit,
476→      },
477→    )
478→    .collect<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>();
479→
480→  const values: WorkspaceDecisionSummary[] = [];
481→
482→  for (const row of rows) {
483→    const [projectRows] = await input.surreal
484→      .query<[Array<RecordId<"project", string>>]>(
485→        "SELECT VALUE out FROM belongs_to WHERE `in` = $decision AND out IN $projects LIMIT 1;",
486→        {
487→          decision: row.id,
488→          projects: projectRecords,
489→        },
490→      )
491→      .collect<[Array<RecordId<"project", string>>]>();
492→
493→    const project = projectRows[0] ? projectById.get(toRecordIdString(projectRows[0])) : undefined;
