495→    values.push({
496→      id: toRecordIdString(row.id),
497→      name: row.summary,
498→      status: row.status,
499→      ...(row.priority ? { priority: row.priority } : {}),
500→      ...(project ? { project } : {}),
501→    });
502→  }
503→
504→  return values;
505→}
