27→export function RelationshipList({
28→  relationships,
29→  onEntityClick,
30→}: {
31→  relationships: Relationship[];
32→  onEntityClick: (entityId: string) => void;
33→}) {
34→  const groups = groupByRelationKind(relationships);
35→
36→  if (groups.size === 0) {
37→    return <p className="entity-detail-meta">No relationships found.</p>;
38→  }
39→
40→  return (
41→    <div className="entity-detail-section">
42→      <h4>Relationships</h4>
43→      {Array.from(groups.entries()).map(([key, items]) => {
44→        const direction = items[0].direction;
45→        const kind = items[0].relationKind;
46→        return (
47→          <div key={key} className="relationship-group">
48→            <span className="relationship-group-label">{formatGroupLabel(kind, direction)}</span>
49→            {items.map((item) => (
50→              <button
51→                key={item.id}
52→                type="button"
