  1→import type { CreateWorkspaceRequest, OnboardingAction } from "../../shared/contracts";
  2→import { HttpError } from "./errors";
  3→
  4→const MAX_UPLOAD_BYTES = 2 * 1024 * 1024;
  5→const allowedUploadExtensions = new Set(["md", "txt"]);
  6→
  7→export type IncomingAttachment = {
  8→  fileName: string;
  9→  mimeType: string;
 10→  sizeBytes: number;
 11→  content: string;
 12→};
 13→
 14→export type ParsedIncomingMessage = {
 15→  clientMessageId: string;
 16→  workspaceId: string;
 17→  conversationId?: string;
 18→  text: string;
 19→  onboardingAction?: OnboardingAction;
 20→  attachment?: IncomingAttachment;
 21→};
 22→
 23→const onboardingActions = new Set(["finalize_onboarding", "continue_onboarding"]);
 24→
 25→export function parseCreateWorkspaceRequest(body: unknown):
 26→  | { ok: true; data: CreateWorkspaceRequest }
 27→  | { ok: false; error: string } {
 28→  if (!body || typeof body !== "object") {
 29→    return { ok: false, error: "Body must be an object" };
 30→  }
 31→
 32→  const payload = body as Partial<CreateWorkspaceRequest>;
 33→
 34→  if (!payload.name || payload.name.trim().length === 0) {
 35→    return { ok: false, error: "name is required" };
 36→  }
 37→
 38→  if (!payload.ownerDisplayName || payload.ownerDisplayName.trim().length === 0) {
 39→    return { ok: false, error: "ownerDisplayName is required" };
 40→  }
 41→
 42→  return {
 43→    ok: true,
 44→    data: {
 45→      name: payload.name.trim(),
 46→      ownerDisplayName: payload.ownerDisplayName.trim(),
 47→    },
 48→  };
 49→}
 50→
 51→export async function parseIncomingMessageRequest(
 52→  request: Request,
 53→): Promise<{ ok: true; data: ParsedIncomingMessage } | { ok: false; error: string }> {
 54→  const contentType = request.headers.get("content-type") ?? "";
 55→
 56→  if (contentType.includes("multipart/form-data")) {
 57→    const formData = await request.formData();
 58→
 59→    const clientMessageIdValue = formData.get("clientMessageId");
 60→    const workspaceIdValue = formData.get("workspaceId");
 61→    const conversationIdValue = formData.get("conversationId");
 62→    const textValue = formData.get("text");
 63→    const onboardingActionValue = formData.get("onboardingAction");
 64→
 65→    if (typeof clientMessageIdValue !== "string" || clientMessageIdValue.trim().length === 0) {
 66→      return { ok: false, error: "clientMessageId is required" };
 67→    }
 68→
 69→    if (typeof workspaceIdValue !== "string" || workspaceIdValue.trim().length === 0) {
 70→      return { ok: false, error: "workspaceId is required" };
 71→    }
 72→
 73→    const text = typeof textValue === "string" ? textValue.trim() : "";
 74→
 75→    const fileValue = formData.get("file");
 76→    let attachment: IncomingAttachment | undefined;
 77→    if (fileValue instanceof File) {
 78→      try {
 79→        attachment = await parseIncomingAttachment(fileValue);
 80→      } catch (error) {
 81→        if (error instanceof HttpError) {
 82→          return { ok: false, error: error.message };
 83→        }
 84→        throw error;
 85→      }
 86→    }
 87→
 88→    if (!attachment && text.length === 0) {
 89→      return { ok: false, error: "text is required when no file is uploaded" };
 90→    }
 91→
 92→    const conversationId =
 93→      typeof conversationIdValue === "string" && conversationIdValue.trim().length > 0
 94→        ? conversationIdValue.trim()
 95→        : undefined;
 96→    const onboardingAction = typeof onboardingActionValue === "string" && onboardingActionValue.trim().length > 0
 97→      ? onboardingActionValue.trim()
 98→      : undefined;
 99→    if (onboardingAction && !onboardingActions.has(onboardingAction)) {
100→      return { ok: false, error: "onboardingAction must be finalize_onboarding or continue_onboarding" };
101→    }
102→
103→    return {
104→      ok: true,
105→      data: {
106→        clientMessageId: clientMessageIdValue.trim(),
107→        workspaceId: workspaceIdValue.trim(),
108→        ...(conversationId ? { conversationId } : {}),
109→        text,
110→        ...(onboardingAction ? { onboardingAction: onboardingAction as OnboardingAction } : {}),
111→        ...(attachment ? { attachment } : {}),
112→      },
113→    };
114→  }
115→
116→  let body: unknown;
117→  try {
118→    body = await request.json();
119→  } catch {
120→    return { ok: false, error: "Request body must be valid JSON" };
121→  }
122→
123→  if (!body || typeof body !== "object") {
124→    return { ok: false, error: "Body must be an object" };
125→  }
126→
127→  const payload = body as Partial<ParsedIncomingMessage>;
128→
129→  if (!payload.clientMessageId || payload.clientMessageId.trim().length === 0) {
130→    return { ok: false, error: "clientMessageId is required" };
131→  }
132→
133→  if (!payload.workspaceId || payload.workspaceId.trim().length === 0) {
134→    return { ok: false, error: "workspaceId is required" };
135→  }
136→
137→  if (!payload.text || payload.text.trim().length === 0) {
138→    return { ok: false, error: "text is required" };
139→  }
140→
141→  if (payload.conversationId && payload.conversationId.trim().length === 0) {
142→    return { ok: false, error: "conversationId must not be empty when provided" };
143→  }
144→
145→  if (payload.onboardingAction && !onboardingActions.has(payload.onboardingAction)) {
146→    return { ok: false, error: "onboardingAction must be finalize_onboarding or continue_onboarding" };
147→  }
148→
149→  return {
150→    ok: true,
151→    data: {
152→      clientMessageId: payload.clientMessageId.trim(),
153→      workspaceId: payload.workspaceId.trim(),
154→      ...(payload.conversationId ? { conversationId: payload.conversationId.trim() } : {}),
155→      text: payload.text.trim(),
156→      ...(payload.onboardingAction ? { onboardingAction: payload.onboardingAction } : {}),
157→    },
158→  };
159→}
