 57→async function handleCreateWorkspace(deps: ServerDependencies, request: Request): Promise<Response> {
 58→  const startedAt = performance.now();
 59→  logInfo("workspace.create.started", "Workspace creation started");
 60→
 61→  let body: unknown;
 62→  try {
 63→    body = await request.json();
 64→  } catch {
 65→    return jsonError("Request body must be valid JSON", 400);
 66→  }
 67→
 68→  const parsed = parseCreateWorkspaceRequest(body);
 69→  if (!parsed.ok) {
 70→    return jsonError(parsed.error, 400);
 71→  }
 72→
 73→  logDebug("http.request.validated", "Workspace request validated");
 74→
 75→  const now = new Date();
 76→  const workspaceId = randomUUID();
 77→  const conversationId = randomUUID();
 78→  const ownerId = randomUUID();
 79→
 80→  const workspaceRecord = new RecordId("workspace", workspaceId);
 81→  const conversationRecord = new RecordId("conversation", conversationId);
 82→  const ownerRecord = new RecordId("person", ownerId);
 83→  const starterMessageRecord = new RecordId("message", randomUUID());
 84→  const starterSuggestions = [
 85→    "Describe your primary project and goal",
 86→    "Share the biggest current bottleneck",
 87→    "Upload a plan or spec to extract",
 88→  ];
 89→
 90→  const starterMessage = [
 91→    `Hey ${parsed.data.ownerDisplayName}!`,
 92→    "I'm ready to help you build out your workspace.",
 93→    "Tell me about what you're working on - what's the main project or business you want to track here?",
 94→    "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
 95→  ].join(" ");
 96→
 97→  const transaction = await deps.surreal.beginTransaction();
 98→  try {
 99→    await transaction.create(workspaceRecord).content({
100→      name: parsed.data.name,
101→      status: "active",
102→      onboarding_complete: false,
103→      onboarding_turn_count: 0,
104→      onboarding_summary_pending: false,
105→      onboarding_started_at: now,
106→      created_at: now,
107→      updated_at: now,
108→    });
109→
110→    const ownerEmbedding = await createEmbeddingVector(
111→      deps.embeddingModel,
112→      parsed.data.ownerDisplayName,
113→      deps.config.embeddingDimension,
114→    );
115→    await transaction.create(ownerRecord).content({
116→      name: parsed.data.ownerDisplayName,
117→      ...(ownerEmbedding ? { embedding: ownerEmbedding } : {}),
118→      created_at: now,
119→      updated_at: now,
120→    });
121→
122→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
123→      role: "owner",
124→      added_at: now,
125→    }).output("after");
126→
127→    await transaction.create(conversationRecord).content({
128→      createdAt: now,
129→      updatedAt: now,
130→      workspace: workspaceRecord,
131→      source: "onboarding",
132→      title: "Onboarding",
133→      title_source: "message",
134→    });
135→
136→    await transaction.create(starterMessageRecord).content({
137→      conversation: conversationRecord,
138→      role: "assistant",
139→      text: starterMessage,
140→      suggestions: starterSuggestions,
141→      createdAt: now,
142→    });
143→
144→    await transaction.commit();
145→  } catch (error) {
146→    await transaction.cancel();
147→    logError("workspace.create.failed", "Workspace creation failed", error, {
148→      workspaceId,
149→      conversationId,
150→    });
151→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
152→    return jsonError(errorText, 500);
153→  }
154→
155→  const response: CreateWorkspaceResponse = {
156→    workspaceId,
157→    workspaceName: parsed.data.name,
158→    conversationId,
159→    onboardingComplete: false,
160→  };
161→
162→  logInfo("workspace.create.completed", "Workspace creation completed", {
163→    workspaceId,
164→    conversationId,
165→    durationMs: elapsedMs(startedAt),
166→  });
167→
168→  return jsonResponse(response, 200);
169→}
