      id: row.id,
      label: `${row.kind}: ${row.text.slice(0, 48)}`,
      description: `confidence ${row.confidence.toFixed(2)}`,
      value: `@${row.id}`,
    }));
  }

  function onUploadFile(file: File) {
    setPendingFile(file);
  }

  function onChatInputClickCapture(event: MouseEvent<HTMLDivElement>) {
