        setIsLoading(false);
        stream.close();
        streamRef.current = undefined;

        // Refresh sidebar after stream completes
        if (workspaceId) {
          void refreshSidebar(workspaceId);
        }
      }
    };

    stream.onerror = () => {
      setErrorMessage("SSE stream disconnected");
      setIsLoading(false);
      stream.close();
      streamRef.current = undefined;
    };
  }

  function onStopMessage() {
    if (!streamRef.current) {
      return;
    }

    streamRef.current.close();
    streamRef.current = undefined;
    setIsLoading(false);
  }

  return {
    sessions,
    activeSessionId,
    activeSession,
    activeConversationId,
    isLoading,
    errorMessage,
    suggestions,
    pendingFile,
    branchingFromId,
    inheritedMessageIds,
    chatInputRef,
    onSendMessage,
    onStopMessage,
    onNewConversation,
    onSelectConversation,
    onBranchFromMessage,
    searchMentions,
    onUploadFile,
    onChatInputClickCapture,
    setErrorMessage,
    refreshSidebar,
  };
}

