}

.relationship-item {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.25rem 0.35rem;
  border-radius: 0;
  cursor: pointer;
  font-size: 0.78rem;
  color: var(--card-foreground);
}

.relationship-item:hover {
  background: var(--hover);
}

/* Provenance section */

.provenance-item {
  border: 1px solid var(--border);
  border-radius: 0;
  padding: 0.4rem 0.5rem;
  font-size: 0.76rem;
  color: var(--card-foreground);
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.provenance-evidence {
  font-style: italic;
  color: var(--muted-foreground);
}

.provenance-link {
  color: var(--ring);
  text-decoration: none;
  font-weight: 600;
  font-size: 0.72rem;
  cursor: pointer;
}

.provenance-link:hover {
  text-decoration: underline;
}

/* View tabs */

/* Graph icon on entity card */

.entity-card-graph-link {
  border: none;
  background: transparent;
  color: var(--ring);
  cursor: pointer;
  padding: 0.15rem;
  line-height: 1;
  font-size: 0.8rem;
  border-radius: 0;
}

.entity-card-graph-link:hover {
  background: var(--hover);
}

/* Message highlight animation (graph → chat navigation) */

@keyframes highlight-message {
  0% {
    background: rgba(0, 87, 204, 0.15);
  }
  100% {
    background: transparent;
  }
}

.animate-highlight {
  animation: highlight-message 2s ease-out;
}

/* Branch: inherited messages */
.message-inherited {
