  border-radius: 0;
  background: var(--muted);
  padding: 0.75rem;
  color: var(--destructive);
  font-size: 0.85rem;
}

.feed-error button {
  margin-top: 0.5rem;
  border: 1px solid var(--destructive);
  border-radius: 0;
  background: var(--card);
  color: var(--destructive);
