  flex-direction: column;
  gap: 0.75rem;
}

/* Feed section (tier) */

.feed-section {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  overflow: hidden;
}

.feed-section-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.55rem 0.75rem;
  border-bottom: 1px solid var(--border);
}

.feed-section-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 1.4rem;
  height: 1.4rem;
  border-radius: 0;
  font-size: 0.65rem;
  font-weight: 800;
  line-height: 1;
}

.feed-section-title {
  margin: 0;
  font-size: 0.8rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.feed-section-count {
  font-size: 0.67rem;
  font-weight: 700;
