}

.search-overlay-body {
  flex: 1;
  overflow-y: auto;
  min-height: 0;
}

.search-input-wrapper {
  display: flex;
}

.search-input {
  width: 100%;
  border: 1px solid var(--input);
  border-radius: 0;
  padding: 0.65rem 0.85rem;
  font-size: 0.9rem;
  color: var(--foreground);
  background: var(--background);
  outline: none;
