  gap: 0.5rem;
}

.search-result-card {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--muted);
  padding: 0.6rem 0.7rem;
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

.search-result-card:hover {
  border-color: var(--ring);
  box-shadow: 0 2px 8px oklch(0.08 0 0 / 0.12);
}

.search-result-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.4rem;
}

.search-result-confidence {
  font-size: 0.7rem;
  font-weight: 600;
  color: var(--muted-foreground);
}

.search-result-text {
  margin: 0;
  font-size: 0.84rem;
  font-weight: 600;
  color: var(--foreground);
  line-height: 1.4;
}

.search-result-footer {
  display: flex;
  justify-content: flex-end;
  gap: 0.4rem;
}

.search-result-graph-btn {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  color: var(--ring);
  padding: 0.28rem 0.55rem;
  font-size: 0.72rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s;
}

.search-result-graph-btn:hover {
  background: var(--hover);
}

.search-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 12rem;
  color: var(--muted-foreground);
  font-size: 0.88rem;
}

.search-empty p {
  margin: 0;
}

